@app.cell(hide_code=True)
def regions_table(mo, widget_ui):
    """Display and interact with regions via table."""
    _regions = widget_ui.value.get("regions", [])

    table_data = [
        {
            "ID": r["id"],
            "Label": r.get("label", ""),
            "Start": f"{r['start']:.3f}s",
            "End": f"{r['end']:.3f}s",
            "Duration": f"{r['end'] - r['start']:.3f}s",
        }
        for r in _regions
    ]

    table = mo.ui.table(table_data, selection="single", label="Audio Regions")
    table
    return (table,)


@app.cell(hide_code=True)
def sync_table_to_widget(mo, table, widget):
    """Seek to selected table row."""
    if not table.value:
        mo.stop(True)

    selected = table.value[0]
    region_id = selected["ID"]

    for r in widget.regions:
        if r["id"] == region_id:
            widget.current_time = r["start"]
            widget.selected_region_id = region_id
            break

    mo.callout(f"🎯 Jumped to: **{selected['Label']}**", kind="info")
    return


