@app.cell(hide_code=True)
def export_handler(export_btn, mo, widget_ui):
    """Handle export button click."""
    import json

    if not export_btn.value:
        mo.stop(True)

    json_output = json.dumps(widget_ui.value.get("regions", []), indent=2)
    mo.vstack(
        [
            mo.callout("✅ Exported successfully!", kind="success"),
            mo.ui.code_editor(value=json_output, language="json", disabled=True),
        ]
    )
    return


@app.cell(hide_code=True)
def documentation(mo):
    mo.md("""
    ---

    ## How It Works

    This widget combines:
    - **[anywidget](https://anywidget.dev/)** - Portable widget framework
    - **[wavesurfer.js](https://wavesurfer.xyz/)** - Audio visualization (loaded from CDN)
    - **[marimo](https://marimo.io/)** - Reactive Python notebooks

    ### Key Features

    - **Bidirectional sync**: Python ↔ JavaScript state automatically synchronized via traitlets
    - **Multi-pitch audio**: Generated sample uses 3 musical notes (A4, C5, E5) forming A major chord
    - **File upload support**: Upload your own audio files (MP3, WAV, OGG, M4A)
    - **Self-contained**: Works immediately - no build step, no external dependencies
    - **Interactive**: Drag regions, click table rows, play audio - everything updates reactively

    ### Use Cases

    - Audio transcription and annotation
    - Podcast chapter marking
    - Music analysis (verse/chorus/bridge)
    - Language learning with sentence-level audio

    ---

    **Resources**:
    [wavesurfer.js docs](https://wavesurfer.xyz/docs/) •
    [anywidget guide](https://anywidget.dev/en/getting-started/) •
    [marimo gallery](https://marimo.io/gallery)
    """)
    return


